const prefix = env.get('CONTEXT_PREFIX') || '';

if (flow.get(`${prefix}initialized`)) {
    return [msg, null];
}
if (flow.get(`${prefix}degraded`)) {
    return null;
}
const buffer = flow.get(`${prefix}state_buffer`) || [];
buffer.push(msg);
flow.set(`${prefix}state_buffer`, buffer);
if (!flow.get(`${prefix}check_running`)) {
    flow.set(`${prefix}check_running`, true);
    flow.set(`${prefix}retries`, 0);
    return [null, msg];
}

return null;

const prefix = env.get('CONTEXT_PREFIX') || '';
const maxRetries = env.get('MAX_RETRIES') || 20;
const retries = flow.get(`${prefix}retries`) || 0;

if (global.get('initializers.ready', 'initializers') === true) {
    flow.set(`${prefix}check_running`, false);
    return [msg, null];
}
if (retries >= maxRetries) {
    flow.set(`${prefix}check_running`, false);
    msg.timedOut = true;
    return [null, msg];
}
flow.set(`${prefix}retries`, retries + 1);
return [null, msg];

const prefix = env.get('CONTEXT_PREFIX') || '';
flow.set(`${prefix}initialized`, true);
flow.set(`${prefix}degraded`, false);
flow.set(`${prefix}check_running`, false);

const buffer = flow.get(`${prefix}state_buffer`) || [];
flow.set(`${prefix}state_buffer`, []);

for (const bufferedMsg of buffer) {
    node.send([bufferedMsg, null]);
}

const prefix = env.get('CONTEXT_PREFIX') || '';
flow.set(`${prefix}degraded`, true);
flow.set(`${prefix}initialized`, false);
flow.set(`${prefix}check_running`, false);
flow.set(`${prefix}state_buffer`, []);

msg.timedOut = true;
return msg;

const payload = msg.payload;

// Only process messages with a battery field
if (payload.battery === undefined || payload.battery === null) {
    return null;
}

// Derive device key from topic: zigbee2mqtt/{device_name}
const topicParts = msg.topic.split('/');
if (topicParts.length < 2) return null;
const deviceKey = topicParts[1];

// Skip Z2M system topics
if (deviceKey === 'bridge' || deviceKey === 'group') return null;

// Derive friendly name from key — title case the naming convention
const derivedName = deviceKey
    .replace(/_/g, ' ')
    .replace(/\b\w/g, c => c.toUpperCase());

// Look up catalog overrides and model battery specs
const registry = global.get('config.deviceRegistry') || {};
const deviceEntry = registry.devices?.[deviceKey];
const friendlyName = deviceEntry?.friendly_name || derivedName;
const modelId = deviceEntry?.model_id;
let batterySpec = null;

if (modelId) {
    batterySpec = registry.models?.[modelId]?.battery || null;
    if (!batterySpec) {
        node.warn(`No battery spec for model ${modelId} (${deviceKey})`);
    }
}

// Parse battery level
const batteryLevel = typeof payload.battery === 'number'
    ? payload.battery
    : parseFloat(payload.battery);

if (isNaN(batteryLevel)) return null;

// Always proceed — registry absence is never a gate
msg.deviceKey = deviceKey;
msg.device = {
    friendly_name: friendlyName,
    battery: batterySpec  // may be null — downstream handles gracefully
};
msg.batteryLevel = batteryLevel;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
node.status({ fill: 'grey', shape: 'dot', text: formatStatus(`${deviceKey}: ${batteryLevel}%`) });

return msg;

const { deviceKey, device, batteryLevel } = msg;
const thresholds = global.get('config')?.thresholds?.battery
    || { warning: 35, critical: 15 };

// Determine new state
const newState = batteryLevel < thresholds.critical ? 'critical'
    : batteryLevel < thresholds.warning ? 'low'
    : 'normal';

// Load persisted battery states
const batteryStates = flow.get('battery_states') || {};
const previous = batteryStates[deviceKey] || { state: 'normal', level: null };
const previousState = previous.state;

// Always update level
batteryStates[deviceKey] = {
    state: newState,
    level: batteryLevel,
    last_notified_critical: previous.last_notified_critical || null
};
flow.set('battery_states', batteryStates);

// No state change — nothing to do
if (newState === previousState) {
    return [null, msg];
}

// State changed — pass forward with transition info
msg.newState = newState;
msg.previousState = previousState;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
node.status({
    fill: newState === 'critical' ? 'red' : newState === 'low' ? 'yellow' : 'green',
    shape: newState === 'critical' ? 'ring' : 'dot',
    text: formatStatus(`${device.friendly_name}: ${batteryLevel}% (${newState})`)
});

return [msg, null];

const { deviceKey, device, batteryLevel, newState, previousState } = msg;

msg.topic = `highland/event/battery/${newState}`;
msg.payload = JSON.stringify({
    timestamp: new Date().toISOString(),
    source: 'battery_monitor',
    entity: deviceKey,
    friendly_name: device.friendly_name,
    level: batteryLevel,
    previous_state: previousState,
    new_state: newState,
    battery: device.battery
});

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const stateColors = { normal: 'green', low: 'yellow', critical: 'red' };
node.status({
    fill: stateColors[newState] || 'grey',
    shape: newState === 'critical' ? 'ring' : 'dot',
    text: formatStatus(`${newState}: ${device.friendly_name}`)
});

return msg;

const { deviceKey, device, batteryLevel, newState, previousState } = msg;

// Determine if this transition warrants a notification
const shouldNotify =
    (newState === 'low') ||
    (newState === 'critical') ||
    (newState !== 'low' && previousState === 'critical') ||
    (newState !== 'low' && previousState === 'low' && newState === 'normal');

// low → normal is silent recovery
if (previousState === 'low' && newState === 'normal') {
    return null;
}

if (!shouldNotify) return null;

const notifications = global.get('config')?.notifications;
const adminOnly = notifications?.defaults?.admin_only || ['joseph'];
const targets = adminOnly.map(p => `people.${p}.ha_companion`);

const isCritical = newState === 'critical';
const isRecovery = newState !== 'critical' && newState !== 'low';

// Handle critical repeat timer
const batteryStates = flow.get('battery_states') || {};
const deviceState = batteryStates[deviceKey] || {};

if (isCritical) {
    // Start/restart 24hr repeat timer
    const timers = flow.get('battery_timers', 'volatile') || {};
    if (timers[deviceKey]) clearTimeout(timers[deviceKey]);

    timers[deviceKey] = setTimeout(() => {
        // Re-notify after 24hrs if still critical
        const states = flow.get('battery_states') || {};
        if (states[deviceKey]?.state === 'critical') {
            node.send({
                payload: JSON.stringify({
                    timestamp: new Date().toISOString(),
                    targets,
                    severity: 'high',
                    title: `Battery Critical: ${device.friendly_name}`,
                    message: `${device.friendly_name} battery is ${states[deviceKey].level}% — needs replacement (${device.battery?.quantity}× ${device.battery?.type})`,
                    group: 'battery_alerts'
                }),
                topic: 'highland/event/notify'
            });
        }
        // Clear timer handle
        const t = flow.get('battery_timers', 'volatile') || {};
        delete t[deviceKey];
        flow.set('battery_timers', t, 'volatile');
    }, 24 * 60 * 60 * 1000);

    flow.set('battery_timers', timers, 'volatile');

    // Record notification time
    deviceState.last_notified_critical = new Date().toISOString();
    batteryStates[deviceKey] = deviceState;
    flow.set('battery_states', batteryStates);

} else if (isRecovery) {
    // Cancel repeat timer
    const timers = flow.get('battery_timers', 'volatile') || {};
    if (timers[deviceKey]) {
        clearTimeout(timers[deviceKey]);
        delete timers[deviceKey];
        flow.set('battery_timers', timers, 'volatile');
    }
}

// Build notification
const severity = isCritical ? 'high' : isRecovery ? 'low' : 'medium';
const title = isCritical ? `Battery Critical: ${device.friendly_name}`
    : isRecovery ? `Battery Recovered: ${device.friendly_name}`
    : `Battery Low: ${device.friendly_name}`;
const message = isCritical
    ? `${device.friendly_name} battery is ${batteryLevel}% — needs replacement (${device.battery?.quantity}× ${device.battery?.type})`
    : isRecovery
    ? `${device.friendly_name} battery has recovered to ${batteryLevel}%`
    : `${device.friendly_name} battery is ${batteryLevel}% — plan replacement soon (${device.battery?.quantity}× ${device.battery?.type})`;

msg.topic = 'highland/event/notify';
msg.payload = JSON.stringify({
    timestamp: new Date().toISOString(),
    source: 'battery_monitor',
    targets,
    severity,
    title,
    message,
    group: 'battery_alerts'
});

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
node.status({
    fill: isCritical ? 'red' : isRecovery ? 'green' : 'yellow',
    shape: isCritical ? 'ring' : 'dot',
    text: formatStatus(title)
});

return msg;

const batteryStates = flow.get('battery_states') || {};
const notifications = global.get('config')?.notifications;
const adminOnly = notifications?.defaults?.admin_only || ['joseph'];
const targets = adminOnly.map(p => `people.${p}.ha_companion`);
const registry = global.get('config.deviceRegistry') || {};

const now = Date.now();
const twentyFourHours = 24 * 60 * 60 * 1000;
const timers = {};

for (const [deviceKey, deviceState] of Object.entries(batteryStates)) {
    if (deviceState.state !== 'critical') continue;

    const device = registry.devices?.[deviceKey];
    if (!device) continue;

    const lastNotified = deviceState.last_notified_critical
        ? new Date(deviceState.last_notified_critical).getTime()
        : 0;
    const elapsed = now - lastNotified;
    const remaining = twentyFourHours - elapsed;

    const notifyAndReschedule = () => {
        const states = flow.get('battery_states') || {};
        if (states[deviceKey]?.state !== 'critical') return;
        node.send({
            payload: JSON.stringify({
                timestamp: new Date().toISOString(),
                targets,
                severity: 'high',
                title: `Battery Critical: ${device.friendly_name}`,
                message: `${device.friendly_name} battery is ${states[deviceKey].level}% — needs replacement (${device.battery?.quantity}× ${device.battery?.type})`,
                group: 'battery_alerts'
            }),
            topic: 'highland/event/notify'
        });
        states[deviceKey].last_notified_critical = new Date().toISOString();
        flow.set('battery_states', states);
    };

    if (remaining <= 0) {
        // Overdue — notify immediately then set fresh 24hr timer
        notifyAndReschedule();
        timers[deviceKey] = setTimeout(notifyAndReschedule, twentyFourHours);
    } else {
        // Not yet due — resume from where we left off
        timers[deviceKey] = setTimeout(notifyAndReschedule, remaining);
    }
}

flow.set('battery_timers', timers, 'volatile');

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const count = Object.keys(timers).length;
node.status({
    fill: count > 0 ? 'yellow' : 'green',
    shape: count > 0 ? 'ring' : 'dot',
    text: formatStatus(`${count} critical timer(s) recovered`)
});

node.send({
    topic: 'highland/state/battery/states',
    payload: JSON.stringify({
        timestamp: new Date().toISOString(),
        source: 'battery_monitor',
        states: batteryStates
    }),
    retain: true,
    qos: 1
});

return null;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const batteryStates = flow.get('battery_states') || {};

msg.topic = 'highland/state/battery/states';
msg.retain = true;
msg.qos = 1;
msg.payload = JSON.stringify({
    timestamp: new Date().toISOString(),
    source: 'battery_monitor',
    states: batteryStates
});

node.status({
    fill: 'green',
    shape: 'dot',
    text: formatStatus(`${Object.keys(batteryStates).length} device(s) published`)
});

return msg;
